package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche products based on ISDA standard model.
 * <p>
 * A CDS tranche is a slice of a CDS index portfolio, with protection only on losses
 * between the attachment and detachment points.
 * <p>
 * The pricer uses the homogeneous pool assumption on the underlying index,
 * pricing the tranche as a synthetic instrument with tranche-specific loss allocation.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for the underlying CDS index.
   */
  private final IsdaHomogenousCdsIndexProductPricer underlyingPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.underlyingPricer = new IsdaHomogenousCdsIndexProductPricer(formula);
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return underlyingPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche product.
   * <p>
   * The present value of the product is based on {@code referenceDate}.
   * This is typically the valuation date, or cash settlement date if the product is associated with a {@code Trade}.
   * <p>
   * This method can calculate the clean or dirty present value, see {@link PriceType}.
   * If calculating the clean value, the accrued interest is calculated based on the step-in date.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    if (isExpired(tranche, ratesProvider)) {
      return CurrencyAmount.of(tranche.getCurrency(), 0d);
    }

    // For now, use simple approximation: price the underlying index and scale by tranche size
    CurrencyAmount underlyingPv = underlyingPricer.presentValue(
        tranche.getUnderlyingIndex(), ratesProvider, referenceDate, priceType, refData);

    // Scale by tranche notional relative to index notional
    double trancheSize = tranche.getDetachmentPoint() - tranche.getAttachmentPoint();
    double scaleFactor = (tranche.getNotional() * trancheSize) / tranche.getUnderlyingIndex().getNotional();

    return underlyingPv.multipliedBy(scaleFactor);
  }

  /**
   * Calculates the present value sensitivity of the product.
   * <p>
   * The present value sensitivity of the product is the sensitivity of present value to the underlying curves.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder presentValueSensitivity(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    if (isExpired(tranche, ratesProvider)) {
      return PointSensitivityBuilder.none();
    }

    PointSensitivityBuilder underlyingSensi = underlyingPricer.priceSensitivity(
        tranche.getUnderlyingIndex(), ratesProvider, referenceDate, refData);

    // Scale by tranche notional relative to index notional
    double trancheSize = tranche.getDetachmentPoint() - tranche.getAttachmentPoint();
    double scaleFactor = (tranche.getNotional() * trancheSize) / tranche.getUnderlyingIndex().getNotional();

    return underlyingSensi.multipliedBy(scaleFactor);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the price of the CDS tranche product, which is the present value per unit notional.
   * <p>
   * This method can calculate the clean or dirty price, see {@link PriceType}.
   * If calculating the clean price, the accrued interest is calculated based on the step-in date.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    CurrencyAmount pv = presentValue(tranche, ratesProvider, referenceDate, priceType, refData);
    double normalizedNotional = tranche.getBuySell().normalize(tranche.getNotional());
    if (normalizedNotional == 0d) {
      return 0d;
    }
    return pv.getAmount() / normalizedNotional;
  }

  /**
   * Calculates the price sensitivity of the product.
   * <p>
   * The price sensitivity of the product is the sensitivity of price to the underlying curves.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder priceSensitivity(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    if (isExpired(tranche, ratesProvider)) {
      return PointSensitivityBuilder.none();
    }

    PointSensitivityBuilder underlyingSensi = underlyingPricer.priceSensitivity(
        tranche.getUnderlyingIndex(), ratesProvider, referenceDate, refData);

    // Scale by tranche size
    double trancheSize = tranche.getDetachmentPoint() - tranche.getAttachmentPoint();
    double scaleFactor = trancheSize;

    return underlyingSensi.multipliedBy(scaleFactor);
  }

  //-------------------------------------------------------------------------
  /**
   * Checks if the tranche has expired.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @return true if expired
   */
  private boolean isExpired(ResolvedCdsTranche tranche, CreditRatesProvider ratesProvider) {
    return !tranche.getProtectionEndDate().isAfter(ratesProvider.getValuationDate());
  }
}

